apm = ElasticAPM(app)

# Database setup
DB_NAME = 'performance_test.db'


def init_db():
    conn = sqlite3.connect(DB_NAME)
    cursor = conn.cursor()
    cursor.execute('''
        CREATE TABLE IF NOT EXISTS users (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            username TEXT NOT NULL,
            email TEXT NOT NULL,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
        )
    ''')
    cursor.execute('''
        CREATE TABLE IF NOT EXISTS orders (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            user_id INTEGER,
            product_name TEXT NOT NULL,
            amount REAL NOT NULL,
            status TEXT DEFAULT 'pending',
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            FOREIGN KEY (user_id) REFERENCES users (id)
        )
    ''')
    conn.commit()
    conn.close()


def get_db_connection():
    conn = sqlite3.connect(DB_NAME)
    conn.row_factory = sqlite3.Row
    return conn


@capture_span('database.query', span_type='db', span_subtype='sqlite', span_action='query')
def execute_query(query, params=None):
    conn = get_db_connection()
    cursor = conn.cursor()
    
    if params:
        cursor.execute(query, params)
    else:
        cursor.execute(query)
    
    if query.strip().upper().startswith('SELECT'):
        results = cursor.fetchall()
        conn.close()
        return [dict(row) for row in results]
    else:
        conn.commit()
        last_id = cursor.lastrowid
        conn.close()
        return last_id


@capture_span('business_logic.process_data')
def process_data(data):
    time.sleep(random.uniform(0.01, 0.05))
    
    processed = {
        'original': data,
        'processed_at': time.time(),
        'hash': hash(str(data))
    }
    
    label(data_size=len(str(data)))
    
    return processed


@capture_span('external_service.call')
def simulate_external_api_call():
    time.sleep(random.uniform(0.1, 0.3))
    
    if random.random() < 0.1:
        raise Exception("External API timeout")
    
    return {'status': 'success', 'data': 'external_response'}


@app.before_request
def before_request():
    set_custom_context({
        'request_id': request.headers.get('X-Request-ID', 'unknown'),
        'user_agent': request.headers.get('User-Agent', 'unknown'),
        'ip_address': request.remote_addr
    })


@app.route('/health', methods=['GET'])
def health_check():
    return jsonify({'status': 'healthy', 'timestamp': time.time()})


@app.route('/api/users', methods=['POST'])
def create_user():
    try:
        data = request.get_json()
        
        set_custom_context({
            'operation': 'create_user',
            'request_data': data
        })
        
        username = data.get('username')
        email = data.get('email')
        
        if not username or not email:
            return jsonify({'error': 'Username and email are required'}), 400
        
        with capture_span('validation.user_data'):
            if '@' not in email:
                return jsonify({'error': 'Invalid email format'}), 400
        
        user_id = execute_query(
            'INSERT INTO users (username, email) VALUES (?, ?)',
            (username, email)
        )
        
        set_user_context(
            user_id=user_id,
            username=username,
            email=email
        )
        
        label(user_created=True, user_id=user_id)
        
        return jsonify({
            'id': user_id,
            'username': username,
            'email': email,
            'message': 'User created successfully'
        }), 201
        
    except Exception as e:
        logger.error(f"Error creating user: {str(e)}")
        apm.capture_exception()
        return jsonify({'error': 'Internal server error'}), 500


