@app.route('/api/users/<int:user_id>', methods=['GET'])
def get_user(user_id):
    try:
        set_custom_context({
            'operation': 'get_user',
            'user_id': user_id
        })
        
        users = execute_query('SELECT * FROM users WHERE id = ?', (user_id,))
        
        if not users:
            return jsonify({'error': 'User not found'}), 404
        
        user = users[0]
        
        orders = execute_query(
            'SELECT * FROM orders WHERE user_id = ? ORDER BY created_at DESC',
            (user_id,)
        )
        
        set_user_context(
            user_id=user_id,
            username=user['username']
        )
        
        label(has_orders=len(orders) > 0, orders_count=len(orders))
        
        return jsonify({
            'user': user,
            'orders': orders
        })
        
    except Exception as e:
        logger.error(f"Error fetching user: {str(e)}")
        apm.capture_exception()
        return jsonify({'error': 'Internal server error'}), 500


@app.route('/api/orders', methods=['POST'])
def create_order():
    try:
        data = request.get_json()
        
        set_custom_context({
            'operation': 'create_order',
            'request_data': data
        })
        
        user_id = data.get('user_id')
        product_name = data.get('product_name')
        amount = data.get('amount')
        
        if not all([user_id, product_name, amount]):
            return jsonify({'error': 'Missing required fields'}), 400
        
        users = execute_query('SELECT * FROM users WHERE id = ?', (user_id,))
        if not users:
            return jsonify({'error': 'User not found'}), 404
        
        processed_data = process_data(data)
        
        try:
            external_result = simulate_external_api_call()
            set_custom_context({'external_api_response': external_result})
        except Exception as e:
            logger.warning(f"External API call failed: {str(e)}")
            apm.capture_exception()
        
        order_id = execute_query(
            'INSERT INTO orders (user_id, product_name, amount) VALUES (?, ?, ?)',
            (user_id, product_name, amount)
        )
        
        set_user_context(user_id=user_id)
        label(order_created=True, order_id=order_id, amount=amount)
        
        return jsonify({
            'id': order_id,
            'user_id': user_id,
            'product_name': product_name,
            'amount': amount,
            'status': 'pending',
            'message': 'Order created successfully'
        }), 201
        
    except Exception as e:
        logger.error(f"Error creating order: {str(e)}")
        apm.capture_exception()
        return jsonify({'error': 'Internal server error'}), 500


@app.route('/api/orders/<int:order_id>/status', methods=['PUT'])
def update_order_status(order_id):
    try:
        data = request.get_json()
        new_status = data.get('status')
        
        set_custom_context({
            'operation': 'update_order_status',
            'order_id': order_id,
            'new_status': new_status
        })
        
        if new_status not in ['pending', 'processing', 'completed', 'cancelled']:
            return jsonify({'error': 'Invalid status'}), 400
        
        orders = execute_query('SELECT * FROM orders WHERE id = ?', (order_id,))
        if not orders:
            return jsonify({'error': 'Order not found'}), 404
        
        execute_query(
            'UPDATE orders SET status = ? WHERE id = ?',
            (new_status, order_id)
        )
        
        label(status_updated=True, new_status=new_status)
        
        return jsonify({
            'id': order_id,
            'status': new_status,
            'message': 'Order status updated successfully'
        })
        
    except Exception as e:
        logger.error(f"Error updating order status: {str(e)}")
        apm.capture_exception()
        return jsonify({'error': 'Internal server error'}), 500


@app.route('/api/analytics/summary', methods=['GET'])
def get_analytics_summary():
    try:
        set_custom_context({'operation': 'get_analytics_summary'})
        
        with capture_span('analytics.count_users'):
            user_count = execute_query('SELECT COUNT(*) as count FROM users')[0]['count']
        
        with capture_span('analytics.count_orders'):
            order_count = execute_query('SELECT COUNT(*) as count FROM orders')[0]['count']
        
        with capture_span('analytics.calculate_revenue'):
            revenue = execute_query('SELECT SUM(amount) as total FROM orders')[0]['total'] or 0
        
        with capture_span('analytics.orders_by_status'):
            orders_by_status = execute_query(
                'SELECT status, COUNT(*) as count FROM orders GROUP BY status'
            )
        
        label(
            total_users=user_count,
            total_orders=order_count,
            total_revenue=revenue
        )
        
        return jsonify({
            'total_users': user_count,
            'total_orders': order_count,
            'total_revenue': revenue,
            'orders_by_status': orders_by_status
        })
        
    except Exception as e:
        logger.error(f"Error generating analytics: {str(e)}")
        apm.capture_exception()
        return jsonify({'error': 'Internal server error'}), 500


